function abrirCalculadoraTempo(){const modal=document.getElementById("modal-calculadora-tempo");if(modal){modal.style.display="block";document.body.style.overflow="hidden"}}function fecharCalculadoraTempo(){const modal=document.getElementById("modal-calculadora-tempo");if(modal){modal.style.display="none";document.body.style.overflow="auto"}}function limparCalculadoraTempo(){document.getElementById("tempo-horas").value="";document.getElementById("tempo-minutos").value="";document.getElementById("tempo-segundos").value="";document.getElementById("pace-minutos").value="";document.getElementById("pace-segundos-input").value="";document.getElementById("distancia-input").value="";document.getElementById("resultado-calculo").style.display="none"}function calcularValores(){const tempoHoras=parseFloat(document.getElementById("tempo-horas").value)||0;const tempoMinutos=parseFloat(document.getElementById("tempo-minutos").value)||0;const tempoSegundos=parseFloat(document.getElementById("tempo-segundos").value)||0;const paceMinutos=parseFloat(document.getElementById("pace-minutos").value)||0;const paceSegundosInput=parseFloat(document.getElementById("pace-segundos-input").value)||0;const distancia=parseFloat(document.getElementById("distancia-input").value)||0;const tempoTotalSegundos=tempoHoras*3600+tempoMinutos*60+tempoSegundos;const paceSegundosPorKm=paceMinutos*60+paceSegundosInput;const tempoPreenchido=tempoTotalSegundos>0;const pacePreenchido=paceSegundosPorKm>0;const distanciaPreenchida=distancia>0;const valoresPreenchidos=[tempoPreenchido,pacePreenchido,distanciaPreenchida].filter(Boolean).length;if(valoresPreenchidos<2){mostrarErro("Preencha pelo menos 2 campos para calcular o terceiro.");return}if(valoresPreenchidos===3){const tempoCalculado=distancia*paceSegundosPorKm;const diferenca=Math.abs(tempoTotalSegundos-tempoCalculado);if(diferenca>5){mostrarErro("Os valores informados não são consistentes entre si. Verifique os dados.");return}else{mostrarResultado("Todos os valores estão corretos e consistentes!");return}}let resultado="";if(!tempoPreenchido&&pacePreenchido&&distanciaPreenchida){const tempoCalculadoSegundos=distancia*paceSegundosPorKm;const tempoFormatado=formatarTempo(tempoCalculadoSegundos);resultado=`Tempo necessário: <strong>${tempoFormatado}</strong>`;const horas=Math.floor(tempoCalculadoSegundos/3600);const minutos=Math.floor(tempoCalculadoSegundos%3600/60);const segundos=Math.round(tempoCalculadoSegundos%60);document.getElementById("tempo-horas").value=horas;document.getElementById("tempo-minutos").value=minutos;document.getElementById("tempo-segundos").value=segundos}else if(tempoPreenchido&&!pacePreenchido&&distanciaPreenchida){const paceCalculadoSegundos=tempoTotalSegundos/distancia;const paceFormatado=formatarPace(paceCalculadoSegundos);resultado=`Pace necessário: <strong>${paceFormatado}</strong>`;const minutos=Math.floor(paceCalculadoSegundos/60);const segundos=Math.round(paceCalculadoSegundos%60);document.getElementById("pace-minutos").value=minutos;document.getElementById("pace-segundos-input").value=segundos}else if(tempoPreenchido&&pacePreenchido&&!distanciaPreenchida){const distanciaCalculada=tempoTotalSegundos/paceSegundosPorKm;resultado=`Distância percorrida: <strong>${distanciaCalculada.toFixed(2)} km</strong>`;document.getElementById("distancia-input").value=distanciaCalculada.toFixed(2)}mostrarResultado(resultado)}function formatarTempo(segundosTotais){const horas=Math.floor(segundosTotais/3600);const minutos=Math.floor(segundosTotais%3600/60);const segundos=Math.round(segundosTotais%60);let resultado="";if(horas>0){resultado+=`${horas}h `}if(minutos>0||horas>0){resultado+=`${minutos}min `}resultado+=`${segundos}seg`;return resultado.trim()}function formatarPace(segundosPorKm){const minutos=Math.floor(segundosPorKm/60);const segundos=Math.round(segundosPorKm%60);return`${minutos}:${segundos.toString().padStart(2,"0")}/km`}function mostrarResultado(texto){const resultadoContainer=document.getElementById("resultado-calculo");const resultadoTexto=document.getElementById("resultado-texto");resultadoTexto.innerHTML=texto;resultadoContainer.style.display="block";resultadoContainer.scrollIntoView({behavior:"smooth",block:"nearest"})}function mostrarErro(texto){const resultadoContainer=document.getElementById("resultado-calculo");const resultadoTexto=document.getElementById("resultado-texto");const resultadoBox=document.querySelector(".resultado-box");resultadoBox.style.background="#dc3545";resultadoTexto.innerHTML=`⚠️ ${texto}`;resultadoContainer.style.display="block";setTimeout(()=>{resultadoBox.style.background="linear-gradient(135deg, #FF6B35, #2E86AB)"},3e3);resultadoContainer.scrollIntoView({behavior:"smooth",block:"nearest"})}document.addEventListener("click",function(e){const modal=document.getElementById("modal-calculadora-tempo");if(e.target===modal){fecharCalculadoraTempo()}});document.addEventListener("keydown",function(e){if(e.key==="Escape"){fecharCalculadoraTempo()}});document.addEventListener("DOMContentLoaded",function(){const inputs=["tempo-horas","tempo-minutos","tempo-segundos","pace-minutos","pace-segundos-input","distancia-input"];inputs.forEach(id=>{const input=document.getElementById(id);if(input){input.addEventListener("input",function(){clearTimeout(this.calcTimeout);this.calcTimeout=setTimeout(()=>{const valoresPreenchidos=contarValoresPreenchidos();if(valoresPreenchidos>=2){calcularValores()}},500)})}})});function contarValoresPreenchidos(){const tempoHoras=parseFloat(document.getElementById("tempo-horas").value)||0;const tempoMinutos=parseFloat(document.getElementById("tempo-minutos").value)||0;const tempoSegundos=parseFloat(document.getElementById("tempo-segundos").value)||0;const paceMinutos=parseFloat(document.getElementById("pace-minutos").value)||0;const paceSegundosInput=parseFloat(document.getElementById("pace-segundos-input").value)||0;const distancia=parseFloat(document.getElementById("distancia-input").value)||0;const tempoTotalSegundos=tempoHoras*3600+tempoMinutos*60+tempoSegundos;const paceSegundosPorKm=paceMinutos*60+paceSegundosInput;const tempoPreenchido=tempoTotalSegundos>0;const pacePreenchido=paceSegundosPorKm>0;const distanciaPreenchida=distancia>0;return[tempoPreenchido,pacePreenchido,distanciaPreenchida].filter(Boolean).length}